const Q_ECONOMICS_2013=[{"id": "objective>Economics>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about the subject being done. Since the subject is mentioned in the question id as 'Economics', the correct answer is 'Economics'.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economy in which both the public and private sectors contribute to economic growth is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">feudal economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is an economic system that features characteristics of both capitalism and socialism. A mixed economic system allows a level of private economic freedom in the use of capital, but also allows for governments to interfere in economic activities in order to achieve social aims.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard deviation of a given data is 53, what is the variance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2082</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2809</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2808</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2209</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">S.d = √V <br/> Square both side <br/> V= S.d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/> = 53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  = 2,809</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following set of statistical tools is used for further economic analysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The median and standard deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mean and mode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mean and standard deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mode and median</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economic analysis, the mean and standard deviation are often used together. The mean provides a measure of central tendency, giving an average value for the data set, while the standard deviation provides a measure of dispersion, showing how spread out the data is from the mean. Therefore, the correct option is 'The mean and standard deviation'.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of the range as a measure of dispersion is that, it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can be used to calculate open-ended distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">makes use of all values of observations in a distribution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes all the values into consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is useful for further statistical calculations</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Range refers to the difference between each series' minimum and maximum values. The range offers us a good indication of how dispersed the data is, but we need other measures of variability to discover the dispersion of data from central tendency measurements. A range is the most common and easily understandable measure of dispersion. It is the difference between two extreme observations of the data set.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the median of the following set of data 35, 10, 14, 38, 15, 18, 22, 30 and 28.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">38</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the median, re-arrange the data thus: 10, 14, 15, 18, (<strong>22</strong>), 28, 30, 35, 38  <br/>  Median = 22</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in demand without a corresponding change in supply will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and an increase in equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and a decrease in equilibrium quantity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When  the demand increases while supply remains constant, there will be an excess demand over supply, also there will be an increase in equilibrium price and quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the price of a commodity will result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in demand </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in price of a commodity will generally lead to a decrease in the quantity of the commodity demanded per time period.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of a bicycle changes from ₦120 to ₦80 and the quantity bought changes from 300 to 500 units, the elasticity of demand for bicycle is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">66.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">price</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80 - 120<hr size=\"1\" />120</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-40<hr size=\"1\" />120</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">- 33.3%</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500-300<hr size=\"1\" />300</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />300</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />3</td></tr></table></div>  <br/>  = 66.7  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">66.7<hr size=\"1\" />33.3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-2.0</td></tr></table></div> <br/> Therefore e = 2 since price elasticity of demand is always negative.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> From the graph above, the price elasticity of demand is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unifairly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph is perfectly inelastic or zero elastic because it is vertical to the y- axis. This is so because a change in price (either increase or decrease) has no affect on quantity bought e.g salt</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the assumptions of the cardinalist approach is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diminishing marginal rate of substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the consistency and transitivity of choice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that total utility depends on the quantity of the commodities consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unstable marginal utility  of money </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cardinalist approach asserts that utility can be measured and quantified. It means, it is possible to express utility that an individual derives from consuming a commodity in quantitative terms. Thus, a person may express the utility he derives from consuming an apple as 10 utils or 20 utils. Moreover, it allows consumers to compare and define the difference in utilities perceived in two commodites. Thus, it allows an individual to state that commodity A (accruing a utility of 20 utils) gives double the utility of commodity B ( which accrues a utility of 10 utils).</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction derived from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distribution of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of goods and services</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction derived from the consumption of a particular commodity. Utility is a measure of preferences over some set of goods and services. </div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the indifference curve above, a consumer will prefer combination</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><strong>F</strong></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><strong>S</strong></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><strong>M</strong></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><strong>K</strong></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Consumer will prefer point <strong>S</strong> since point S has a higher indifference curve and Utility is higher than the other points on the graph. </div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : INDIFFERENCE CURVE"}, {"id": "objective>Economics>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major factors that brings about changes in supply is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market discrimination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of storage facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cost of storage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">incentives granted to workers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The available of facilities to store produced goods would affect the quantity of goods supplied to the market. Producers maybe willing to produce, but if there are no storage facilities to store the manufactured goods pending when the demand for it will arise, producers would cut down on production thereby affecting the quantity of goods supplied. <br/> Others factors are:  <br/> (i) Natural Conditions (ii) Technical Progress (iii) Change in Factor Prices (iv) Transport Improvements (v) Calamities (vi) Monopolies (vii) Fiscal Policy.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If <strong>P</strong> = 1/4(Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + 10), what is the quantity supplied at ₦14?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">46</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">(Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">10)</td></tr></table></div>  <br/>  P = ₦14  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">14</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">(Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">10)</td></tr></table></div>  <br/>  56 = Qs + 10  <br/>  Qs = 56 - 10  <br/>  = 46</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the supply of a product is elastic, a small reduction in price will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduce the cost of production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead to no change in the quantity supplied</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> If supply is elastic, an increase in demand will cause only a small rise in price, but a significant increase in demand. If supply is inelastic, an increase in demand will cause a large rise in price but only a small increase in demand.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of beverages by firms in a monopolistic market is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">derived demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint demand</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a more realistic scenario that actually occurs in the real world. In monopolistic competition, there are still a large number of buyers as well as sellers. But they all do not sell homogeneous products. The products are similar but all sellers sell slightly differentiated products. <br/>  <br/> Now the consumers have the preference of choosing one product over another. The sellers can also charge a marginally higher price since they may enjoy some market power. So the sellers become the price setters to a certain extent. <br/>  <br/> For example, the market for cereals is a monopolistic competition. The products are all similar but slightly differentiated in terms of taste and flavours. Another such example is toothpaste.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of a commodity is fixed below equilibrium, this will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the of a commodity is fixed below the equilibrium price,  there will be excess demand over supply which will lead to shortage.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the criticisms of the price mechanism is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producers are sovereign</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it provides low degree of freedom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it widens the inequitable gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers are sovereign</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price mechanism, which is the economic concept that the free market system is sufficient to determine the price of goods and services through supply and demand, is often criticized for widening the inequitable gap. This is because it can lead to wealth disparities, where those who can afford to pay more for goods and services get more, while those who cannot afford to pay as much get less.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, government can reduce the cost of accommodation by fixing rent</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at the prevailing rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">above the equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">below the equilibrium price</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government can reduce the cost of accommodation by fixing the rent at a maximum price. Maximum prices occur when a government sets a legal limit on the price of a good or service – with the aim of reducing prices below the market equilibrium price. Governments try to control the rate charged for rent by keeping the cost of renting below a certain level. However, setting the price below equilibrium maximum will cause a shortage – demand will be greater than supply.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a refinery achieves a reduction in cost by purchasing and transporting crude in large quantities, it enjoys</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economics of scale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">specialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">division of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diseconomics of scale</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Economies of scale are the cost advantages that enterprises obtain due to size, output, or scale of operation, with cost per unit of output generally decreasing with increasing scale as fixed costs are spread out over more units of output.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An isoquant lying above to the right of another represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a higher output level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over-capacity utilization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a lower output level</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An isoquant is also called as-equal product curve or production indifference curve or constant product curve. An isoquant lying above to the right of another will represent a higher output level.</div>", "topic": "THEORY OF PRODUCTION (2) : LAWS OF PRODUCTION"}, {"id": "objective>Economics>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> From the graph above, <strong>R</strong> represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R represents Total cost which is the total economic cost of production and is made up of variable cost and fixed cost. <br/> M is variable cost while T is fixed cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The optimum level output of the firm is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">BC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">BS</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Point OB is the optimal level of output which indicates the point of intersection of MR and MC.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total revenue of the firm is represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">GHEF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GHJC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EFJC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GHOB</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total revenue of the firm is point GHOb (GH representing the price and OB representing quantity). Hence, TR = GH × OB</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A measure of national income used as a comparison of standard of living among nations is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">net national product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross domestic product </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross national product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">per capita income</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income (PCI) or average income measures the average income earned per person in a given area (city, region, country, etc.) in a specified year. It is calculated by dividing the area's total income by its total population. Per capita income is national income divided by population size. Per capita is used to measure the standard of living between two countries.</div>", "topic": "NATIONAL INCOME : USES & REASONS FOR MEASURING NATIONAL INCOME"}, {"id": "objective>Economics>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speculative demand for money is inversely related to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speculative motive relates to the desire to hold one's resources in liquid form to take advantage of future changes in the rate of interest or bond prices. It is inversely related with the Bond prices and the rate of interest.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Mr K obtains a ₦50,000 loan from a bank for the purpose of providing household needs, the demand for money is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transactionary and speculative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transactionary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">speculative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">precautionary and speculative</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for money is said to be transactionary when it is used for day-to-day transactions such as buying goods and services. In this case, Mr K is obtaining a loan to provide for household needs, which falls under day-to-day transactions. Therefore, the demand for money is transactionary. Speculative demand for money is when people hold money to speculate on future changes in interest rates or prices.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used by the Central Bank of Nigeria to control inflation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tariffs on imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tax rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Discount rate </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discount rate is the minimum interest rate set by the central bank of a country. It is used in controlling inflation.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If <strong>CBN</strong> reduces money supply, the interest rate will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fluctuate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unchanged</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The interest rates will be high if CBN reduces money supply. This is done to discourage borrowing and control the flow of money in the economy. It is mostly done when there is excess money in circulation.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an expansionary fiscal policy action is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in the corporate profit tax rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in welfare payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">purchase of government securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in the bank rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lowering taxes and raising government spending. Social security measures taken by the govt. is an example of expansionary policy. Subsidies, Tax rate cuts etc are other examples There is a few example of expansionary fiscal policy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tax on land will ultimately fall</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">party on agents and users</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entirely on users</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entirely on owners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partly on users and owners</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A land value tax is a progressive tax, in that the tax burden falls on titleholders in proportion to the value of locations, the ownership of which is highly correlated with overall wealth and income.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the goals of development plans in Nigeria is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the profitability of multinational businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improve the country's GDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">achieve higher standard of living for the citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deregulate the economy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sustainable Development Goals are a global call to action to end poverty, protect the earth's environment and climate, and ensure that people everywhere can enjoy peace and prosperity. These are the goals the UN is working on in Nigeria. In terms of SDG driven development, goal eight lends itself in particular to the Nigerian reality: \"to promote sustained, inclusive and sustainable economic growth, full and productive employment and decent work for all\".</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Life insurance companies contribute to economic development by holding a part of their assets in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long-term financial instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money market instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and near money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-term financial instruments</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The life insurance sector may contribute to economic growth by its very mechanism of savings mobilisation and thereby performing an intermediation role in the economy. This ensures that capital is provided to deficient units who are in need of capital to finance their working capital requirements and invest in technology thereby resulting in an increase in output. Life insurance is an institution in capital market.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to add value to Nigeria agricultural produce, there is need to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cultivate high breed crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">process them into finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopt modern storage methods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertize them in European markets</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most international consumers would rather have the agricultural produce processed and packaged in a way that facilitates their delivery and entry into the export market. Changing a raw agricultural product into something new through processing, cooling, drying, extracting, packaging or any other type of value addition that differentiates the final product from the original raw commodity has a value chain reaction that not only yields revenue but also creates jobs and boosts the Gross Domestic Product (GDP).</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main reason for low agricultural produce in West Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the presence of large-scale agro-allied industries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high dependency ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over dependence on agriculture for subsistence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of crude implements in farming process</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems of agricultural development in West Africa are: <br/> - land tenure system <br/> - inadquate finance or credit facilities <br/> - poor transportation systems <br/> - inadequate storage and processing <br/> - inadequate farm input <br/> - illiteracy of the farmers <br/> - lack of basic amenities <br/> - use of crude implements <br/> - lack of technical know- how   etc</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important determinant for the location of a brick industry is the availability of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important determinant for the location of a brick industry is the availability of raw materials. This is because the production process in a brick industry heavily relies on raw materials like clay, sand etc. If these materials are not readily available, the cost of production would increase significantly due to transportation costs. Therefore, to minimize costs, brick industries are usually located near the source of raw materials.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, efficiency in public corporations can be achieved through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public offer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nationalization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is the transfer of ownership of property or businesses from a government to a privately owned entity.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government participation in the oil industry was necessitated by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">annual increase in production.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of OPEC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high demand for crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">huge investment outlay</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government participation in the oil industry was necessitated by the huge investment outlay. The oil industry requires a large amount of capital for exploration, drilling, refining, and distribution. This huge investment outlay often necessitates government participation to ensure that the industry is properly funded and managed.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The deregulation of the petroleum sector in Nigeria will bring about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficiency in pricing and distribution of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an end to the importation of fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an end to foreign firms' dominance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixing appropriate production quotas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In this context it is the removal of regulations and restrictions such as subsidy paid by the Nigerian government on petroleum products. One of the main reasons for deregulating the petroleum sector is to make the sector competitive, efficient and with lower product prices.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing characteristic of consumer co-operative society is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maximum number of shareholders is 20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members are the owners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members are the workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the minimum number of shareholder is 5</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Some of the main characteristics of consumers co-operative stores are as follows: These are known as consumer co-operative stores. These are owned and managed by the consumers themselves in order to eliminate middlemen and to obtain their requirements at reasonable prices. They are also termed as consumer co­operative societies.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of partnership business is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">difficulty in the transfer of shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distrust among members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited liability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large capital outlay</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of partnership business is the difficulty in the transfer of shares. In a partnership, shares cannot be transferred to a new partner without the consent of all existing partners. This can make it difficult for partners to exit the business or for new partners to join.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of labour force in Nigeria can be improved by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establishing more tertiary institutions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creating sufficient job opportunities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging the study of science and technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing more skills acquisition centres</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of the labour force depends on education and training, physique, and health. There is evidence that physique has been greatly improved by increases in the standard of living in the 20th century.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}, {"id": "objective>Economics>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of emigration on a country's population is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in job opportunities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in dependency ratio</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effect on the emigrating country is a reduction in the population and labour force and an increase in the population of the new country of residence.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A measure for preventing the external value of the Naira from falling is for the government to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase its spending with foreign reserve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell its own currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">buy its own currency with foreign reserve</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bank can buy its own currency by using foreign currency that it has in its own reserves. This not only cuts off the currency's depreciation, but also controls the money supply by reducing the amount in circulation. The same is true if the central bank decides to do the opposite—by selling its own currency if it appreciates too much.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fiscal policy instrument that can influence the demand pattern in an economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">income rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tariff</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy refers to the use of government revenue collection (taxation) and expenditure (spending) to influence a country's economy. The primary instruments of fiscal policy are government spending and taxation. Therefore, government spending is a fiscal policy instrument that can influence the demand pattern in an economy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main achievements of the Economic Commission for Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eliminating trade restrictions among states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging transport and communicating development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guaranteeing a steady flow of foreign investment into Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">providing the machinery for collaboration on monetary issues</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Commission for Africa (ECA) is a regional commission of the United Nations that aims to promote the economic and social development of its member states. One of its main achievements is encouraging transport and communication development among African states. This is because the ECA has been instrumental in promoting infrastructure development, including transport and communication, to facilitate trade and economic growth in the region.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : ECA, IMF"}, {"id": "objective>Economics>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of interest charged on loans depends largely on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the prevailing exchange rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal efficiency of capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the risk associated with the loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the prevailing tax rate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of interest charged on loans is largely dependent on the risk associated with the loan. This is because the higher the risk of the loan, the higher the interest rate charged to compensate for the potential risk of default. The prevailing exchange rate, marginal efficiency of capital, and the prevailing tax rate may affect the interest rate, but they are not the primary factors.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A valid explanation for real wage growth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the rate of productivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rising cost of capital accumulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a contraction of employment in service industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the quantity of labour</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Real productivity increase was thus more than four times the increase in real wages, which means that three quarter of the achieved labour productivity growth was not paid out in form of wages. In Hungary, Romania, Portugal and Greece real wages went down in the last 16 years, while productivity increased.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Mr X lost his clerical job at a store and searched for a similar job for ten months before finding one, this implies that Mr X was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">structurally unemployed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">frictionally unemployed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonally unemployment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclically unemployed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Frictional unemployment is a type of unemployment. It is sometimes called search unemployment and can be based on the circumstances of the individual. It is time spent between jobs when a worker is searching for a job or transitioning from one job to another</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}];
